#!/usr/bin/env bash
# greenfield-ubnt-deployment-for-a.sh — Greenfield UBNT deployment for an 80-person office SOP walkthrough for UBNT/UniFi 企业 Wi-Fi 工程.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="UBNT/UniFi 企业 Wi-Fi 工程"
WORKFLOW="Greenfield UBNT deployment for an 80-person office"

usage() {
  cat <<EOF
greenfield-ubnt-deployment-for-a.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./greenfield-ubnt-deployment-for-a.sh             # interactive
  ./greenfield-ubnt-deployment-for-a.sh --dry-run
  ./greenfield-ubnt-deployment-for-a.sh --json
  ./greenfield-ubnt-deployment-for-a.sh --explain
  ./greenfield-ubnt-deployment-for-a.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "Greenfield UBNT deployment for an 80-person office" 工作流。

一句话: From "we need Wi-Fi in this new office" to "users are roaming smoothly and we have monitoring" — full deployment lifecycle (evidence: [T03-S004, T03-S008, T03-S005])

入门 SOP 共 7 步, 失败模式自检 8 项。

相关心智模型:
  • 容量优先, 覆盖次之 (Capacity-first, coverage second): 80 人密集办公的 Wi-Fi 瓶颈不是覆盖, 是同信道干扰 (CCI) — 加 AP 反而让网络更慢; 工程师先算 airtime budget, 后摆 AP.
  • Retry rate > RSSI (重试率比信号强度更能定位问题): 客户跟你说 "信号差", 你先要 retry % 和 channel utilization, 不要 RSSI — RSSI 满格但 retry 30% (业内估计 — CCI 阈值) 是 CCI /

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**Requirements gathering**: count concurrent users (80 people × 1.5-2 devices = 120-160 active clients), application SLA (voice / video / data), client device mix (Android / iOS / Windows / IoT), backhaul (internet egress + wired backbone). Skip → wrong AP count from day 1, redesign in month 2."
  "**Predictive design or rule-of-thumb sizing**: Ekahau / Hamina predictive (商业项目) OR vonNagy rule-of-thumb (~25 active 5GHz clients per AP → 6-8 APs for 80 people). Skip → arbitrary AP count, dead zones in conf rooms / hot zones at desks."
  "**Hardware procurement (BOM)**: Controller (UDM-Pro or UCG-Max for 80 ppl; NOT Cloud Key Gen1), APs (U6 Pro / U7 Pro x6-8), PoE+ switches (≥30W/port for U7), cabling. Skip → blocked install + last-minute hardware swaps."
  "**Physical install**: ceiling-mount APs, line-of-sight to most users, even spacing, NOT clustered above server room. Skip → coverage holes that no Tx-power tuning can fix."
  "**Controller config + adopt**: install Network App, adopt all APs, create SSIDs (WPA3-Personal or WPA2/3-Enterprise + 802.1X), VLAN segmentation (corp / guest / IoT). Skip → flat network, security incidents."
  "**Initial RF tune**: Tx Power Auto→Medium, channels 1/6/11 (2.4) + DFS-aware 5GHz, 80MHz width 5GHz / 20MHz 2.4GHz, Min RSSI -75 dBm. Skip → CCI catastrophe day 1."
  "**Validation + handoff**: WiFiman walk all zones, iperf3 from each conf room, document RSSI / SNR per zone, customer training. Skip → silent failures until first user complaint."
)
declare -a FAILURE_MODES=(
  "**F1**: Build with Cloud Key Gen1 to save \$200, hit OOM at 60+ clients, retroactively buy UDM-Pro — wastes 1 week of rework (evidence: [T03-S023] r/Ubiquiti complaints; Track 02 Pitfall #6)"
  "**F2**: Skip predictive AND skip post-install survey — discover 2 dead zones in conference rooms after move-in, requires AP add-on + rewire (evidence: [T03-S003] Ekahau best practices; Track 02 Pitfall #2)"
  "**F3**: Set Tx Power Max on all APs because \"more signal = better,\" cause CCI catastrophe, throughput crashes when meeting starts (evidence: Track 02 Pitfall #1; [T03-S001] vonNagy)"
  "**Sources**:"
  "[Primary] iFeelTech UniFi blueprints (T03-S008, collected 2026-06-02)"
  "[Primary] Crosstalk Solutions blog + YouTube (T03-S004, T03-S005)"
  "[Reference] vonNagy capacity-first (T03-S001)"
  "[Reference] r/Ubiquiti deployment threads (T03-S023)"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "greenfield-ubnt-deployment-for-a-walkthrough"
fi
